import{_ as a,o as t,c as o,ae as r}from"./chunks/framework.BAOUhEwF.js";const p=JSON.parse('{"title":"Type Alias: GlobalAttrs","description":"","frontmatter":{},"headers":[],"relativePath":"api/ts/ts/dom/type-aliases/GlobalAttrs.md","filePath":"api/ts/ts/dom/type-aliases/GlobalAttrs.md"}'),s={name:"api/ts/ts/dom/type-aliases/GlobalAttrs.md"};function l(c,e,d,n,i,h){return t(),o("div",null,[...e[0]||(e[0]=[r('<p><a href="./../../../README.html"><strong>@vastare/fundatio v1.0.3</strong></a></p><hr><h1 id="type-alias-globalattrs" tabindex="-1">Type Alias: GlobalAttrs <a class="header-anchor" href="#type-alias-globalattrs" aria-label="Permalink to &quot;Type Alias: GlobalAttrs&quot;">​</a></h1><blockquote><p><strong>GlobalAttrs</strong> = <code>object</code></p></blockquote><p>Defined in: <a href="https://github.com/VastareDev/fundatio/blob/d3ab436af7cfe8418cc253b09c8672bc7c80a189/src/ts/dom.ts#L53" target="_blank" rel="noreferrer">ts/dom.ts:53</a></p><p>A curated, safe subset of HTML global attributes commonly applied to elements.</p><h2 id="remarks" tabindex="-1">Remarks <a class="header-anchor" href="#remarks" aria-label="Permalink to &quot;Remarks&quot;">​</a></h2><p>This type intentionally focuses on widely used global attributes and provides a generic escape hatch via <a href="#attrs">GlobalAttrs.attrs</a> for less common cases.</p><p>Security rules enforced by <a href="./../functions/applyGlobalAttrs.html">applyGlobalAttrs</a>:</p><ul><li>Blocks inline event handler attributes like <code>onclick</code></li><li>Blocks the raw <code>style</code> attribute. Use <a href="#style">GlobalAttrs.style</a> instead</li></ul><h2 id="properties" tabindex="-1">Properties <a class="header-anchor" href="#properties" aria-label="Permalink to &quot;Properties&quot;">​</a></h2><h3 id="aria" tabindex="-1">aria? <a class="header-anchor" href="#aria" aria-label="Permalink to &quot;aria?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>aria</strong>: <code>Record</code>&lt;<code>string</code>, <a href="./AttrValue.html"><code>AttrValue</code></a>&gt;</p></blockquote><p>Defined in: <a href="https://github.com/VastareDev/fundatio/blob/d3ab436af7cfe8418cc253b09c8672bc7c80a189/src/ts/dom.ts#L174" target="_blank" rel="noreferrer">ts/dom.ts:174</a></p><p>ARIA attribute values applied as <code>aria-*</code> attributes.</p><h4 id="remarks-1" tabindex="-1">Remarks <a class="header-anchor" href="#remarks-1" aria-label="Permalink to &quot;Remarks&quot;">​</a></h4><p>Keys are appended to <code>aria-</code>. Example: <code>{ label: &quot;Close&quot; }</code> becomes <code>aria-label=&quot;Close&quot;</code>.</p><hr><h3 id="attrs" tabindex="-1">attrs? <a class="header-anchor" href="#attrs" aria-label="Permalink to &quot;attrs?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>attrs</strong>: <code>Record</code>&lt;<code>string</code>, <a href="./AttrValue.html"><code>AttrValue</code></a>&gt;</p></blockquote><p>Defined in: <a href="https://github.com/VastareDev/fundatio/blob/d3ab436af7cfe8418cc253b09c8672bc7c80a189/src/ts/dom.ts#L187" target="_blank" rel="noreferrer">ts/dom.ts:187</a></p><p>Escape hatch for additional attributes not modeled above.</p><h4 id="remarks-2" tabindex="-1">Remarks <a class="header-anchor" href="#remarks-2" aria-label="Permalink to &quot;Remarks&quot;">​</a></h4><p>This exists to keep the API practical without turning Fundatio into a full DOM abstraction layer.</p><p>Security rules:</p><ul><li>Attributes starting with <code>on</code> are rejected (blocks inline event handlers)</li><li>The <code>style</code> attribute is rejected (use <a href="#style">GlobalAttrs.style</a>)</li></ul><hr><h3 id="classname" tabindex="-1">className? <a class="header-anchor" href="#classname" aria-label="Permalink to &quot;className?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>className</strong>: <code>string</code></p></blockquote><p>Defined in: <a href="https://github.com/VastareDev/fundatio/blob/d3ab436af7cfe8418cc253b09c8672bc7c80a189/src/ts/dom.ts#L69" target="_blank" rel="noreferrer">ts/dom.ts:69</a></p><p>The element class string.</p><h4 id="remarks-3" tabindex="-1">Remarks <a class="header-anchor" href="#remarks-3" aria-label="Permalink to &quot;Remarks&quot;">​</a></h4><p>This maps to <code>class</code> in HTML. Use this instead of passing <code>class</code> through <a href="#attrs">GlobalAttrs.attrs</a>.</p><hr><h3 id="contenteditable" tabindex="-1">contentEditable? <a class="header-anchor" href="#contenteditable" aria-label="Permalink to &quot;contentEditable?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>contentEditable</strong>: <code>&quot;true&quot;</code> | <code>&quot;false&quot;</code> | <code>&quot;plaintext-only&quot;</code></p></blockquote><p>Defined in: <a href="https://github.com/VastareDev/fundatio/blob/d3ab436af7cfe8418cc253b09c8672bc7c80a189/src/ts/dom.ts#L142" target="_blank" rel="noreferrer">ts/dom.ts:142</a></p><p>Whether the element is editable.</p><h4 id="remarks-4" tabindex="-1">Remarks <a class="header-anchor" href="#remarks-4" aria-label="Permalink to &quot;Remarks&quot;">​</a></h4><p>Use sparingly. Many apps are better served by explicit form controls.</p><hr><h3 id="dataset" tabindex="-1">dataset? <a class="header-anchor" href="#dataset" aria-label="Permalink to &quot;dataset?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>dataset</strong>: <code>Record</code>&lt;<code>string</code>, <a href="./AttrValue.html"><code>AttrValue</code></a>&gt;</p></blockquote><p>Defined in: <a href="https://github.com/VastareDev/fundatio/blob/d3ab436af7cfe8418cc253b09c8672bc7c80a189/src/ts/dom.ts#L165" target="_blank" rel="noreferrer">ts/dom.ts:165</a></p><p>Dataset values applied as <code>data-*</code> attributes.</p><h4 id="remarks-5" tabindex="-1">Remarks <a class="header-anchor" href="#remarks-5" aria-label="Permalink to &quot;Remarks&quot;">​</a></h4><p>Keys map to <code>HTMLElement.dataset</code> keys (camelCase), and values are coerced to strings.</p><p>Example: <code>{ trackingId: &quot;123&quot; }</code> becomes <code>data-tracking-id=&quot;123&quot;</code>.</p><hr><h3 id="dir" tabindex="-1">dir? <a class="header-anchor" href="#dir" aria-label="Permalink to &quot;dir?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>dir</strong>: <code>&quot;ltr&quot;</code> | <code>&quot;rtl&quot;</code> | <code>&quot;auto&quot;</code></p></blockquote><p>Defined in: <a href="https://github.com/VastareDev/fundatio/blob/d3ab436af7cfe8418cc253b09c8672bc7c80a189/src/ts/dom.ts#L88" target="_blank" rel="noreferrer">ts/dom.ts:88</a></p><p>Text direction of the element&#39;s content.</p><hr><h3 id="draggable" tabindex="-1">draggable? <a class="header-anchor" href="#draggable" aria-label="Permalink to &quot;draggable?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>draggable</strong>: <code>boolean</code></p></blockquote><p>Defined in: <a href="https://github.com/VastareDev/fundatio/blob/d3ab436af7cfe8418cc253b09c8672bc7c80a189/src/ts/dom.ts#L118" target="_blank" rel="noreferrer">ts/dom.ts:118</a></p><p>Whether the element is draggable.</p><hr><h3 id="hidden" tabindex="-1">hidden? <a class="header-anchor" href="#hidden" aria-label="Permalink to &quot;hidden?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>hidden</strong>: <code>boolean</code></p></blockquote><p>Defined in: <a href="https://github.com/VastareDev/fundatio/blob/d3ab436af7cfe8418cc253b09c8672bc7c80a189/src/ts/dom.ts#L104" target="_blank" rel="noreferrer">ts/dom.ts:104</a></p><p>Whether the element is hidden.</p><h4 id="remarks-6" tabindex="-1">Remarks <a class="header-anchor" href="#remarks-6" aria-label="Permalink to &quot;Remarks&quot;">​</a></h4><p>Mirrors the <code>hidden</code> boolean attribute.</p><hr><h3 id="id" tabindex="-1">id? <a class="header-anchor" href="#id" aria-label="Permalink to &quot;id?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>id</strong>: <code>string</code></p></blockquote><p>Defined in: <a href="https://github.com/VastareDev/fundatio/blob/d3ab436af7cfe8418cc253b09c8672bc7c80a189/src/ts/dom.ts#L60" target="_blank" rel="noreferrer">ts/dom.ts:60</a></p><p>The element ID.</p><h4 id="remarks-7" tabindex="-1">Remarks <a class="header-anchor" href="#remarks-7" aria-label="Permalink to &quot;Remarks&quot;">​</a></h4><p>Must be unique within the document.</p><hr><h3 id="lang" tabindex="-1">lang? <a class="header-anchor" href="#lang" aria-label="Permalink to &quot;lang?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>lang</strong>: <code>string</code></p></blockquote><p>Defined in: <a href="https://github.com/VastareDev/fundatio/blob/d3ab436af7cfe8418cc253b09c8672bc7c80a189/src/ts/dom.ts#L83" target="_blank" rel="noreferrer">ts/dom.ts:83</a></p><p>Language of the element&#39;s content.</p><h4 id="remarks-8" tabindex="-1">Remarks <a class="header-anchor" href="#remarks-8" aria-label="Permalink to &quot;Remarks&quot;">​</a></h4><p>Useful when rendering mixed-language documents, or when an element&#39;s content differs from the page language.</p><hr><h3 id="role" tabindex="-1">role? <a class="header-anchor" href="#role" aria-label="Permalink to &quot;role?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>role</strong>: <code>string</code></p></blockquote><p>Defined in: <a href="https://github.com/VastareDev/fundatio/blob/d3ab436af7cfe8418cc253b09c8672bc7c80a189/src/ts/dom.ts#L96" target="_blank" rel="noreferrer">ts/dom.ts:96</a></p><p>Optional ARIA role.</p><h4 id="remarks-9" tabindex="-1">Remarks <a class="header-anchor" href="#remarks-9" aria-label="Permalink to &quot;Remarks&quot;">​</a></h4><p>Prefer native semantics when possible. Only set <code>role</code> when needed.</p><hr><h3 id="spellcheck" tabindex="-1">spellCheck? <a class="header-anchor" href="#spellcheck" aria-label="Permalink to &quot;spellCheck?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>spellCheck</strong>: <code>boolean</code></p></blockquote><p>Defined in: <a href="https://github.com/VastareDev/fundatio/blob/d3ab436af7cfe8418cc253b09c8672bc7c80a189/src/ts/dom.ts#L126" target="_blank" rel="noreferrer">ts/dom.ts:126</a></p><p>Whether spellchecking is enabled for editable content.</p><h4 id="remarks-10" tabindex="-1">Remarks <a class="header-anchor" href="#remarks-10" aria-label="Permalink to &quot;Remarks&quot;">​</a></h4><p>Mirrors <code>spellcheck</code>. This has effect primarily when <code>contentEditable</code> is used.</p><hr><h3 id="style" tabindex="-1">style? <a class="header-anchor" href="#style" aria-label="Permalink to &quot;style?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>style</strong>: <code>Partial</code>&lt;<code>CSSStyleDeclaration</code>&gt;</p></blockquote><p>Defined in: <a href="https://github.com/VastareDev/fundatio/blob/d3ab436af7cfe8418cc253b09c8672bc7c80a189/src/ts/dom.ts#L154" target="_blank" rel="noreferrer">ts/dom.ts:154</a></p><p>Inline style properties to assign to the element.</p><h4 id="remarks-11" tabindex="-1">Remarks <a class="header-anchor" href="#remarks-11" aria-label="Permalink to &quot;Remarks&quot;">​</a></h4><p>This is safer than accepting a raw style string because it avoids the <code>style=&quot;...&quot;</code> attribute injection surface.</p><p>This does not make untrusted input &quot;safe&quot;. If callers build styles from untrusted sources, they must validate inputs appropriately.</p><hr><h3 id="tabindex" tabindex="-1">tabIndex? <a class="header-anchor" href="#tabindex" aria-label="Permalink to &quot;tabIndex?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>tabIndex</strong>: <code>number</code></p></blockquote><p>Defined in: <a href="https://github.com/VastareDev/fundatio/blob/d3ab436af7cfe8418cc253b09c8672bc7c80a189/src/ts/dom.ts#L113" target="_blank" rel="noreferrer">ts/dom.ts:113</a></p><p>Tabbing order.</p><h4 id="remarks-12" tabindex="-1">Remarks <a class="header-anchor" href="#remarks-12" aria-label="Permalink to &quot;Remarks&quot;">​</a></h4><p>Use with care. Setting a tab index on non-interactive elements can reduce usability and accessibility.</p><hr><h3 id="title" tabindex="-1">title? <a class="header-anchor" href="#title" aria-label="Permalink to &quot;title?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>title</strong>: <code>string</code></p></blockquote><p>Defined in: <a href="https://github.com/VastareDev/fundatio/blob/d3ab436af7cfe8418cc253b09c8672bc7c80a189/src/ts/dom.ts#L74" target="_blank" rel="noreferrer">ts/dom.ts:74</a></p><p>Advisory information, typically shown as a tooltip in browsers.</p><hr><h3 id="translate" tabindex="-1">translate? <a class="header-anchor" href="#translate" aria-label="Permalink to &quot;translate?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>translate</strong>: <code>&quot;yes&quot;</code> | <code>&quot;no&quot;</code></p></blockquote><p>Defined in: <a href="https://github.com/VastareDev/fundatio/blob/d3ab436af7cfe8418cc253b09c8672bc7c80a189/src/ts/dom.ts#L134" target="_blank" rel="noreferrer">ts/dom.ts:134</a></p><p>Translation hint for user agents.</p><h4 id="remarks-13" tabindex="-1">Remarks <a class="header-anchor" href="#remarks-13" aria-label="Permalink to &quot;Remarks&quot;">​</a></h4><p>Maps to the <code>translate</code> attribute.</p>',120)])])}const u=a(s,[["render",l]]);export{p as __pageData,u as default};
